+fn write_u32_stderr(mut value: u32) {
+    let mut buf = [0u8; 10];
+    let mut idx = buf.len();
+
+    if value == 0 {
+        let _ = unsafe { syscall::sys_write(libc::STDERR_FILENO, b"0".as_ptr(), 1) };
+        return;
+    }
+
+    while value > 0 {
+        idx -= 1;
+        buf[idx] = b'0' + (value % 10) as u8;
+        value /= 10;
+    }
+
+    let _ = unsafe {
+        syscall::sys_write(
+            libc::STDERR_FILENO,
+            buf[idx..].as_ptr(),
+            buf.len().saturating_sub(idx),
+        )
+    };
+}
